"use strict";(self.webpackChunkmy_blog=self.webpackChunkmy_blog||[]).push([[90182],{66262:(n,s)=>{s.A=(n,s)=>{const e=n.__vccOpts||n;for(const[n,a]of s)e[n]=a;return e}},56305:(n,s,e)=>{e.r(s),e.d(s,{comp:()=>b,data:()=>m});var a=e(20641);const i=e.p+"assets/img/Ciqc1F-FTHGAOVGKAAJe5PD5u9A015.13b967ad.png",l=e.p+"assets/img/Ciqc1F-JXfmAJK8RAAHUliqXmBc629.0eea3699.png",p=e.p+"assets/img/CgqCHl-FTJSAd9oTAAAm0DgOmVo715.74dfad98.png",r=e.p+"assets/img/CgqCHl-FTKGAJNO8AAElldtvsRM104.87f280eb.png",t=e.p+"assets/img/CgqCHl-FTK-AUlLCAADTWhhySe8432.a3e18199.png",o=e.p+"assets/img/Ciqc1F-FTLuAZ-AoAACeZ02hpEg723.d326a483.png",c=e.p+"assets/img/CgqCHl-FTMSAYeP7AAA_pzU2CPA016.525acf57.png",d=e.p+"assets/img/Ciqc1F-FTM2Ae73pAAC0_daI0N4088.d83fd9e2.png",v=e.p+"assets/img/Ciqc1F-FTOGAEWu7AADOU3xBmjA069.fee6b31d.png",u={},b=(0,e(66262).A)(u,[["render",function(n,s){return(0,a.uX)(),(0,a.CE)("div",null,s[0]||(s[0]=[(0,a.Fv)('<h1 id="_24-从-protocol-起手-看服务暴露和服务引用的全流程-上" tabindex="-1"><a class="header-anchor" href="#_24-从-protocol-起手-看服务暴露和服务引用的全流程-上"><span>24 从 Protocol 起手，看服务暴露和服务引用的全流程（上）</span></a></h1><p>在上一课时我们讲解了 Protocol 的核心接口，那本课时我们就以 Protocol 接口为核心，详细介绍整个 Protocol 的核心实现。下图展示了 Protocol 接口的继承关系：</p><figure><img src="'+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Protocol 接口继承关系图</p><p>其中，<strong>AbstractProtocol</strong>提供了一些 Protocol 实现需要的公共能力以及公共字段，它的核心字段有如下三个。</p><ul><li>exporterMap（<code>Map&lt;String, Exporter&lt;?&gt;&gt;</code>类型）：用于存储出去的服务集合，其中的 Key 通过 ProtocolUtils.serviceKey() 方法创建的服务标识，在 ProtocolUtils 中维护了多层的 Map 结构（如下图所示）。首先按照 group 分组，在实践中我们可以根据需求设置 group，例如，按照机房、地域等进行 group 划分，做到就近调用；在 GroupServiceKeyCache 中，依次按照 serviceName、serviceVersion、port 进行分类，最终缓存的 serviceKey 是前面三者拼接而成的。</li></ul><figure><img src="'+l+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>groupServiceKeyCacheMap 结构图</p><ul><li>serverMap（<code>Map&lt;String, ProtocolServer&gt;</code>类型）：记录了全部的 ProtocolServer 实例，其中的 Key 是 host 和 port 组成的字符串，Value 是监听该地址的 ProtocolServer。ProtocolServer 就是对 RemotingServer 的一层简单封装，表示一个服务端。</li><li>invokers（<code>Set&lt;Invoker&lt;?&gt;&gt;</code>类型）：服务引用的集合。</li></ul><p>AbstractProtocol 没有对 Protocol 的 export() 方法进行实现，对 refer() 方法的实现也是委托给了 protocolBindingRefer() 这个抽象方法，然后由子类实现。AbstractProtocol 唯一实现的方法就是 destory() 方法，其首先会遍历 Invokers 集合，销毁全部的服务引用，然后遍历全部的 exporterMap 集合，销毁发布出去的服务，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public void destroy() {</span></span>\n<span class="line"><span>    for (Invoker&lt;?&gt; invoker : invokers) {</span></span>\n<span class="line"><span>        if (invoker != null) {</span></span>\n<span class="line"><span>            invokers.remove(invoker);</span></span>\n<span class="line"><span>            invoker.destroy(); // 关闭全部的服务引用</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    for (String key : new ArrayList&lt;String&gt;(exporterMap.keySet())) {</span></span>\n<span class="line"><span>        Exporter&lt;?&gt; exporter = exporterMap.remove(key);</span></span>\n<span class="line"><span>        if (exporter != null) {</span></span>\n<span class="line"><span>            exporter.unexport(); // 关闭暴露出去的服务</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="export-流程简析" tabindex="-1"><a class="header-anchor" href="#export-流程简析"><span>export 流程简析</span></a></h3><p>了解了 AbstractProtocol 提供的公共能力之后，我们再来分析<strong>Dubbo 默认使用的 Protocol 实现类—— DubboProtocol 实现</strong>。这里我们首先关注 DubboProtocol 的 export() 方法，也就是服务发布的相关实现，如下所示：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public &lt;T&gt; Exporter&lt;T&gt; export(Invoker&lt;T&gt; invoker) throws RpcException {</span></span>\n<span class="line"><span>    URL url = invoker.getUrl();</span></span>\n<span class="line"><span>    // 创建ServiceKey，其核心实现在前文已经详细分析过了，这里不再重复</span></span>\n<span class="line"><span>    String key = serviceKey(url); </span></span>\n<span class="line"><span>    // 将上层传入的Invoker对象封装成DubboExporter对象，然后记录到exporterMap集合中</span></span>\n<span class="line"><span>    DubboExporter&lt;T&gt; exporter = new DubboExporter&lt;T&gt;(invoker, key, exporterMap);</span></span>\n<span class="line"><span>    exporterMap.put(key, exporter);</span></span>\n<span class="line"><span>    ... // 省略一些日志操作</span></span>\n<span class="line"><span>    // 启动ProtocolServer</span></span>\n<span class="line"><span>    openServer(url);</span></span>\n<span class="line"><span>    // 进行序列化的优化处理</span></span>\n<span class="line"><span>    optimizeSerialization(url);</span></span>\n<span class="line"><span>    return exporter;</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-dubboexporter" tabindex="-1"><a class="header-anchor" href="#_1-dubboexporter"><span>1. DubboExporter</span></a></h4><p>这里涉及的第一个点是 DubboExporter 对 Invoker 的封装，DubboExporter 的继承关系如下图所示：</p><figure><img src="'+p+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>DubboExporter 继承关系图</p><p>AbstractExporter 中维护了一个 Invoker 对象，以及一个 unexported 字段（boolean 类型），在 unexport() 方法中会设置 unexported 字段为 true，并调用 Invoker 对象的 destory() 方法进行销毁。</p><p>DubboExporter 也比较简单，其中会维护底层 Invoker 对应的 ServiceKey 以及 DubboProtocol 中的 exportMap 集合，在其 unexport() 方法中除了会调用父类 AbstractExporter 的 unexport() 方法之外，还会清理该 DubboExporter 实例在 exportMap 中相应的元素。</p><h4 id="_2-服务端初始化" tabindex="-1"><a class="header-anchor" href="#_2-服务端初始化"><span>2. 服务端初始化</span></a></h4><p>了解了 Exporter 实现之后，我们继续看 DubboProtocol 中服务发布的流程。从下面这张调用关系图中可以看出，openServer() 方法会一路调用前面介绍的 Exchange 层、Transport 层，并最终创建 NettyServer 来接收客户端的请求。</p><figure><img src="'+r+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>export() 方法调用栈</p><p>下面我们将逐个介绍 export() 方法栈中的每个被调用的方法。</p><p>首先，在 openServer() 方法中会根据 URL 判断当前是否为服务端，只有服务端才能创建 ProtocolServer 并对外服务。如果是来自服务端的调用，会依靠 serverMap 集合检查是否已有 ProtocolServer 在监听 URL 指定的地址；如果没有，会调用 createServer() 方法进行创建。openServer() 方法的具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>private void openServer(URL url) {</span></span>\n<span class="line"><span>    String key = url.getAddress(); // 获取host:port这个地址</span></span>\n<span class="line"><span>    boolean isServer = url.getParameter(IS_SERVER_KEY, true);</span></span>\n<span class="line"><span>    if (isServer) { // 只有Server端才能启动Server对象</span></span>\n<span class="line"><span>        ProtocolServer server = serverMap.get(key);</span></span>\n<span class="line"><span>        if (server == null) { // 无ProtocolServer监听该地址</span></span>\n<span class="line"><span>            synchronized (this) { // DoubleCheck，防止并发问题</span></span>\n<span class="line"><span>                server = serverMap.get(key);</span></span>\n<span class="line"><span>                if (server == null) {</span></span>\n<span class="line"><span>                    // 调用createServer()方法创建ProtocolServer对象</span></span>\n<span class="line"><span>                    serverMap.put(key, createServer(url));</span></span>\n<span class="line"><span>                }</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>        } else { </span></span>\n<span class="line"><span>            // 如果已有ProtocolServer实例，则尝试根据URL信息重置ProtocolServer</span></span>\n<span class="line"><span>            server.reset(url);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>createServer() 方法首先会为 URL 添加一些默认值，同时会进行一些参数值的检测，主要有五个。</p><ul><li>HEARTBEAT_KEY 参数值，默认值为 60000，表示默认的心跳时间间隔为 60 秒。</li><li>CHANNEL_READONLYEVENT_SENT_KEY 参数值，默认值为 true，表示 ReadOnly 请求需要阻塞等待响应返回。在 Server 关闭的时候，只能发送 ReadOnly 请求，这些 ReadOnly 请求由这里设置的 CHANNEL_READONLYEVENT_SENT_KEY 参数值决定是否需要等待响应返回。</li><li>CODEC_KEY 参数值，默认值为 dubbo。你可以回顾 Codec2 接口中 @Adaptive 注解的参数，都是获取该 URL 中的 CODEC_KEY 参数值。</li><li>检测 SERVER_KEY 参数指定的扩展实现名称是否合法，默认值为 netty。你可以回顾 Transporter 接口中 @Adaptive 注解的参数，它决定了 Transport 层使用的网络库实现，默认使用 Netty 4 实现。</li><li>检测 CLIENT_KEY 参数指定的扩展实现名称是否合法。同 SERVER_KEY 参数的检查流程。</li></ul><p>完成上述默认参数值的设置之后，我们就可以通过 Exchangers 门面类创建 ExchangeServer，并封装成 DubboProtocolServer 返回。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>private ProtocolServer createServer(URL url) {</span></span>\n<span class="line"><span>    url = URLBuilder.from(url)</span></span>\n<span class="line"><span>            // ReadOnly请求是否阻塞等待</span></span>\n<span class="line"><span>            .addParameterIfAbsent(CHANNEL_READONLYEVENT_SENT_KEY, Boolean.TRUE.toString())</span></span>\n<span class="line"><span>            // 心跳间隔</span></span>\n<span class="line"><span>            .addParameterIfAbsent(HEARTBEAT_KEY, String.valueOf(DEFAULT_HEARTBEAT))</span></span>\n<span class="line"><span>            .addParameter(CODEC_KEY, DubboCodec.NAME) // Codec2扩展实现</span></span>\n<span class="line"><span>            .build();</span></span>\n<span class="line"><span>    // 检测SERVER_KEY参数指定的Transporter扩展实现是否合法</span></span>\n<span class="line"><span>    String str = url.getParameter(SERVER_KEY, DEFAULT_REMOTING_SERVER); </span></span>\n<span class="line"><span>    if (str != null &amp;&amp; str.length() &gt; 0 &amp;&amp; !ExtensionLoader.getExtensionLoader(Transporter.class).hasExtension(str)) {</span></span>\n<span class="line"><span>        throw new RpcException(&quot;...&quot;);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 通过Exchangers门面类，创建ExchangeServer对象</span></span>\n<span class="line"><span>    ExchangeServer server = Exchangers.bind(url, requestHandler);</span></span>\n<span class="line"><span>    ... // 检测CLIENT_KEY参数指定的Transporter扩展实现是否合法(略)</span></span>\n<span class="line"><span>    // 将ExchangeServer封装成DubboProtocolServer返回</span></span>\n<span class="line"><span>    return new DubboProtocolServer(server);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 createServer() 方法中还有几个细节需要展开分析一下。第一个是创建 ExchangeServer 时，使用的 Codec2 接口实现实际上是 DubboCountCodec，对应的 SPI 配置文件如下：</p><figure><img src="'+t+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Codec2 SPI 配置文件</p><p>DubboCountCodec 中维护了一个 DubboCodec 对象，编解码的能力都是 DubboCodec 提供的，DubboCountCodec 只负责在解码过程中 ChannelBuffer 的 readerIndex 指针控制，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public Object decode(Channel channel, ChannelBuffer buffer) throws IOException {</span></span>\n<span class="line"><span>    int save = buffer.readerIndex(); // 首先保存readerIndex指针位置</span></span>\n<span class="line"><span>    // 创建MultiMessage对象，其中可以存储多条消息</span></span>\n<span class="line"><span>    MultiMessage result = MultiMessage.create(); </span></span>\n<span class="line"><span>    do {</span></span>\n<span class="line"><span>        // 通过DubboCodec提供的解码能力解码一条消息</span></span>\n<span class="line"><span>        Object obj = codec.decode(channel, buffer);</span></span>\n<span class="line"><span>        // 如果可读字节数不足一条消息，则会重置readerIndex指针</span></span>\n<span class="line"><span>        if (Codec2.DecodeResult.NEED_MORE_INPUT == obj) {</span></span>\n<span class="line"><span>            buffer.readerIndex(save);</span></span>\n<span class="line"><span>            break;</span></span>\n<span class="line"><span>        } else { // 将成功解码的消息添加到MultiMessage中暂存</span></span>\n<span class="line"><span>            result.addMessage(obj);</span></span>\n<span class="line"><span>            logMessageLength(obj, buffer.readerIndex() - save);</span></span>\n<span class="line"><span>            save = buffer.readerIndex();</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    } while (true);</span></span>\n<span class="line"><span>    if (result.isEmpty()) { // 一条消息也未解码出来，则返回NEED_MORE_INPUT错误码</span></span>\n<span class="line"><span>        return Codec2.DecodeResult.NEED_MORE_INPUT;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    if (result.size() == 1) { // 只解码出来一条消息，则直接返回该条消息</span></span>\n<span class="line"><span>        return result.get(0);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 解码出多条消息的话，会将MultiMessage返回</span></span>\n<span class="line"><span>    return result;</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>DubboCountCodec、DubboCodec 都实现了第 22 课时介绍的 Codec2 接口，其中 DubboCodec 是 ExchangeCodec 的子类。</p><figure><img src="'+o+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>DubboCountCodec 及 DubboCodec 继承关系图</p><p>我们知道 ExchangeCodec 只处理了 Dubbo 协议的请求头，而 DubboCodec 则是通过继承的方式，在 ExchangeCodec 基础之上，添加了解析 Dubbo 消息体的功能。在第 22 课时介绍 ExchangeCodec 实现的时候，我们重点分析了 encodeRequest() 方法，即 Request 请求的编码实现，其中会调用 encodeRequestData() 方法完成请求体的编码。</p><p>DubboCodec 中就覆盖了 encodeRequestData() 方法，按照 Dubbo 协议的格式编码 Request 请求体，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>protected void encodeRequestData(Channel channel, ObjectOutput out, Object data, String version) throws IOException {</span></span>\n<span class="line"><span>    // 请求体相关的内容，都封装在了RpcInvocation</span></span>\n<span class="line"><span>    RpcInvocation inv = (RpcInvocation) data; </span></span>\n<span class="line"><span>    out.writeUTF(version); // 写入版本号</span></span>\n<span class="line"><span>    String serviceName = inv.getAttachment(INTERFACE_KEY);</span></span>\n<span class="line"><span>    if (serviceName == null) {</span></span>\n<span class="line"><span>        serviceName = inv.getAttachment(PATH_KEY);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 写入服务名称</span></span>\n<span class="line"><span>    out.writeUTF(serviceName);</span></span>\n<span class="line"><span>    // 写入Service版本号</span></span>\n<span class="line"><span>    out.writeUTF(inv.getAttachment(VERSION_KEY));</span></span>\n<span class="line"><span>    // 写入方法名称</span></span>\n<span class="line"><span>    out.writeUTF(inv.getMethodName());</span></span>\n<span class="line"><span>    // 写入参数类型列表</span></span>\n<span class="line"><span>    out.writeUTF(inv.getParameterTypesDesc());</span></span>\n<span class="line"><span>    // 依次写入全部参数</span></span>\n<span class="line"><span>    Object[] args = inv.getArguments();</span></span>\n<span class="line"><span>    if (args != null) {</span></span>\n<span class="line"><span>        for (int i = 0; i &lt; args.length; i++) {</span></span>\n<span class="line"><span>            out.writeObject(encodeInvocationArgument(channel, inv, i));</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 依次写入全部的附加信息</span></span>\n<span class="line"><span>    out.writeAttachments(inv.getObjectAttachments());</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>RpcInvocation 实现了上一课时介绍的 Invocation 接口，如下图所示：</p><figure><img src="'+c+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>RpcInvocation 继承关系图</p><p>下面是 RpcInvocation 中的核心字段，通过读写这些字段即可实现 Invocation 接口的全部方法。</p><ul><li>targetServiceUniqueName（String类型）：要调用的唯一服务名称，其实就是 ServiceKey，即 interface/group:version 三部分构成的字符串。</li><li>methodName（String类型）：调用的目标方法名称。</li><li>serviceName（String类型）：调用的目标服务名称，示例中就是org.apache.dubbo.demo.DemoService。</li><li>parameterTypes（Class&lt;?&gt;[]类型）：记录了目标方法的全部参数类型。</li><li>parameterTypesDesc（String类型）：参数列表签名。</li><li>arguments（Object[]类型）：具体参数值。</li><li>attachments（<code>Map&lt;String, Object&gt;</code>类型）：此次调用的附加信息，可以被序列化到请求中。</li><li>attributes（<code>Map&lt;Object, Object&gt;</code>类型）：此次调用的属性信息，这些信息不能被发送出去。</li><li>invoker（<code>Invoker&lt;?&gt;</code>类型）：此次调用关联的 Invoker 对象。</li><li>returnType（<code>Class&lt;?&gt;</code>类型）：返回值的类型。</li><li>invokeMode（InvokeMode类型）：此次调用的模式，分为 SYNC、ASYNC 和 FUTURE 三类。</li></ul><p>我们在上面的继承图中看到 RpcInvocation 的一个子类—— DecodeableRpcInvocation，它是用来支持解码的，其实现的 decode() 方法正好是 DubboCodec.encodeRequestData() 方法对应的解码操作，在 DubboCodec.decodeBody() 方法中就调用了这个方法，调用关系如下图所示：</p><figure><img src="'+d+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>decode() 方法调用栈</p><p>这个解码过程中有个细节，在 DubboCodec.decodeBody() 方法中有如下代码片段，其中会根据 DECODE_IN_IO_THREAD_KEY 这个参数决定是否在 DubboCodec 中进行解码（DubboCodec 是在 IO 线程中调用的）。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>// decode request.</span></span>\n<span class="line"><span>Request req = new Request(id);</span></span>\n<span class="line"><span>... // 省略Request中其他字段的设置</span></span>\n<span class="line"><span>Object data;</span></span>\n<span class="line"><span>DecodeableRpcInvocation inv;</span></span>\n<span class="line"><span>// 这里会检查DECODE_IN_IO_THREAD_KEY参数</span></span>\n<span class="line"><span>if (channel.getUrl().getParameter(DECODE_IN_IO_THREAD_KEY, DEFAULT_DECODE_IN_IO_THREAD)) {</span></span>\n<span class="line"><span>    inv = new DecodeableRpcInvocation(channel, req, is, proto);</span></span>\n<span class="line"><span>    inv.decode(); // 直接调用decode()方法在当前IO线程中解码</span></span>\n<span class="line"><span>} else { // 这里只是读取数据，不会调用decode()方法在当前IO线程中进行解码</span></span>\n<span class="line"><span>    inv = new DecodeableRpcInvocation(channel, req,</span></span>\n<span class="line"><span>            new UnsafeByteArrayInputStream(readMessageData(is)), proto);</span></span>\n<span class="line"><span>}</span></span>\n<span class="line"><span>data = inv;</span></span>\n<span class="line"><span>req.setData(data); // 设置到Request请求的data字段</span></span>\n<span class="line"><span>return req;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果不在 DubboCodec 中解码，那会在哪里解码呢？你可以回顾第 20 课时介绍的 DecodeHandler（Transport 层），它的 received() 方法也是可以进行解码的，另外，DecodeableRpcInvocation 中有一个 hasDecoded 字段来判断当前是否已经完成解码，这样，三者配合就可以根据 DECODE_IN_IO_THREAD_KEY 参数决定执行解码操作的线程了。</p><p>如果你对线程模型不清楚，可以依次回顾一下 Exchangers、HeaderExchanger、Transporters 三个门面类的 bind() 方法，以及 Dispatcher 各实现提供的线程模型，搞清楚各个 ChannelHandler 是由哪个线程执行的，这些知识点在前面课时都介绍过了，不再重复。这里我们就直接以 AllDispatcher 实现为例给出结论。</p><ul><li>IO 线程内执行的 ChannelHandler 实现依次有：InternalEncoder、InternalDecoder（两者底层都是调用 DubboCodec）、IdleStateHandler、MultiMessageHandler、HeartbeatHandler 和 NettyServerHandler。</li><li>在非 IO 线程内执行的 ChannelHandler 实现依次有：DecodeHandler、HeaderExchangeHandler 和 DubboProtocol$requestHandler。</li></ul><p>在 DubboProtocol 中有一个 requestHandler 字段，它是一个实现了 ExchangeHandlerAdapter 抽象类的匿名内部类的实例，间接实现了 ExchangeHandler 接口，其核心是 reply() 方法，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public CompletableFuture&lt;Object&gt; reply(ExchangeChannel channel, Object message) throws RemotingException {</span></span>\n<span class="line"><span>    ... // 这里省略了检查message类型的逻辑，通过前面Handler的处理，这里收到的message必须是Invocation类型的对象</span></span>\n<span class="line"><span>    Invocation inv = (Invocation) message;</span></span>\n<span class="line"><span>    // 获取此次调用Invoker对象</span></span>\n<span class="line"><span>    Invoker&lt;?&gt; invoker = getInvoker(channel, inv);</span></span>\n<span class="line"><span>    ... // 针对客户端回调的内容，在后面详细介绍，这里不再展开分析</span></span>\n<span class="line"><span>    // 将客户端的地址记录到RpcContext中</span></span>\n<span class="line"><span>    RpcContext.getContext().setRemoteAddress(channel.getRemoteAddress());</span></span>\n<span class="line"><span>    // 执行真正的调用</span></span>\n<span class="line"><span>    Result result = invoker.invoke(inv);</span></span>\n<span class="line"><span>    // 返回结果</span></span>\n<span class="line"><span>    return result.thenApply(Function.identity());</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中 getInvoker() 方法会先根据 Invocation 携带的信息构造 ServiceKey，然后从 exporterMap 集合中查找对应的 DubboExporter 对象，并从中获取底层的 Invoker 对象返回，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>Invoker&lt;?&gt; getInvoker(Channel channel, Invocation inv) throws RemotingException {</span></span>\n<span class="line"><span>    ... // 省略对客户端Callback以及stub的处理逻辑，后面单独介绍</span></span>\n<span class="line"><span>    String serviceKey = serviceKey(port, path, (String) inv.getObjectAttachments().get(VERSION_KEY),</span></span>\n<span class="line"><span>            (String) inv.getObjectAttachments().get(GROUP_KEY));</span></span>\n<span class="line"><span>    DubboExporter&lt;?&gt; exporter = (DubboExporter&lt;?&gt;) exporterMap.get(serviceKey);</span></span>\n<span class="line"><span>    ... //  查找不到相应的DubboExporter对象时，会直接抛出异常，这里省略了这个检测</span></span>\n<span class="line"><span>    return exporter.getInvoker(); // 获取exporter中获取Invoker对象</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>到这里，我们终于见到了对 Invoker 对象的调用，对 Invoker 实现的介绍和分析，在后面课时我们会深入介绍，这里就先专注于 DubboProtocol 的相关内容。</p><h4 id="_3-序列化优化处理" tabindex="-1"><a class="header-anchor" href="#_3-序列化优化处理"><span>3. 序列化优化处理</span></a></h4><p>下面我们回到 DubboProtocol.export() 方法继续分析，在完成 ProtocolServer 的启动之后，export() 方法最后会调用 optimizeSerialization() 方法对指定的序列化算法进行优化。</p><p>这里先介绍一个基础知识，在使用某些序列化算法（例如， Kryo、FST 等）时，为了让其能发挥出最佳的性能，最好将那些需要被序列化的类提前注册到 Dubbo 系统中。例如，我们可以通过一个实现了 SerializationOptimizer 接口的优化器，并在配置中指定该优化器，如下示例代码：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class SerializationOptimizerImpl implements SerializationOptimizer {</span></span>\n<span class="line"><span>    public Collection&lt;Class&gt; getSerializableClasses() {</span></span>\n<span class="line"><span>        List&lt;Class&gt; classes = new ArrayList&lt;&gt;();</span></span>\n<span class="line"><span>        classes.add(xxxx.class); // 添加需要被序列化的类</span></span>\n<span class="line"><span>        return classes;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 DubboProtocol.optimizeSerialization() 方法中，就会获取该优化器中注册的类，通知底层的序列化算法进行优化，序列化的性能将会被大大提升。当然，在进行序列化的时候，难免会级联到很多 Java 内部的类（例如，数组、各种集合类型等），Kryo、FST 等序列化算法已经自动将JDK 中的常用类进行了注册，所以无须重复注册它们。</p><p>下面我们回头来看 optimizeSerialization() 方法，分析序列化优化操作的具体实现细节：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>private void optimizeSerialization(URL url) throws RpcException {</span></span>\n<span class="line"><span>    // 根据URL中的optimizer参数值，确定SerializationOptimizer接口的实现类</span></span>\n<span class="line"><span>    String className = url.getParameter(OPTIMIZER_KEY, &quot;&quot;);</span></span>\n<span class="line"><span>    Class clazz = Thread.currentThread().getContextClassLoader().loadClass(className);</span></span>\n<span class="line"><span>    // 创建SerializationOptimizer实现类的对象</span></span>\n<span class="line"><span>    SerializationOptimizer optimizer = (SerializationOptimizer) clazz.newInstance();</span></span>\n<span class="line"><span>    // 调用getSerializableClasses()方法获取需要注册的类</span></span>\n<span class="line"><span>    for (Class c : optimizer.getSerializableClasses()) {</span></span>\n<span class="line"><span>        SerializableClassRegistry.registerClass(c); </span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    optimizers.add(className);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>SerializableClassRegistry 底层维护了一个 static 的 Map（REGISTRATIONS 字段），registerClass() 方法就是将待优化的类写入该集合中暂存，在使用 Kryo、FST 等序列化算法时，会读取该集合中的类，完成注册操作，相关的调用关系如下图所示：</p><figure><img src="'+v+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>getRegisteredClasses() 方法的调用位置</p><p>按照 Dubbo 官方文档的说法，即使不注册任何类进行优化，Kryo 和 FST 的性能依然普遍优于Hessian2 和 Dubbo 序列化。</p><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h3><p>本课时我们重点介绍了 DubboProtocol 发布一个 Dubbo 服务的核心流程。首先，我们介绍了 AbstractProtocol 这个抽象类为 Protocol 实现类提供的公共能力和字段，然后我们结合 Dubbo 协议对应的 DubboProtocol 实现，讲解了发布一个 Dubbo 服务的核心流程，其中涉及整个服务端核心启动流程、RpcInvocation 实现、DubboProtocol.requestHandler 字段调用 Invoker 对象以及序列化相关的优化处理等内容。</p>',73)]))}]]),m=JSON.parse('{"path":"/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98/24%20%20%E4%BB%8E%20Protocol%20%E8%B5%B7%E6%89%8B%EF%BC%8C%E7%9C%8B%E6%9C%8D%E5%8A%A1%E6%9A%B4%E9%9C%B2%E5%92%8C%E6%9C%8D%E5%8A%A1%E5%BC%95%E7%94%A8%E7%9A%84%E5%85%A8%E6%B5%81%E7%A8%8B%EF%BC%88%E4%B8%8A%EF%BC%89.html","title":"24  从 Protocol 起手，看服务暴露和服务引用的全流程（上）","lang":"zh-CN","frontmatter":{"description":"24 从 Protocol 起手，看服务暴露和服务引用的全流程（上） 在上一课时我们讲解了 Protocol 的核心接口，那本课时我们就以 Protocol 接口为核心，详细介绍整个 Protocol 的核心实现。下图展示了 Protocol 接口的继承关系： Protocol 接口继承关系图 其中，AbstractProtocol提供了一些 Prot...","head":[["meta",{"property":"og:url","content":"https://chenmingxing1012.github.io/blog/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98/24%20%20%E4%BB%8E%20Protocol%20%E8%B5%B7%E6%89%8B%EF%BC%8C%E7%9C%8B%E6%9C%8D%E5%8A%A1%E6%9A%B4%E9%9C%B2%E5%92%8C%E6%9C%8D%E5%8A%A1%E5%BC%95%E7%94%A8%E7%9A%84%E5%85%A8%E6%B5%81%E7%A8%8B%EF%BC%88%E4%B8%8A%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"凡人修码传"}],["meta",{"property":"og:title","content":"24  从 Protocol 起手，看服务暴露和服务引用的全流程（上）"}],["meta",{"property":"og:description","content":"24 从 Protocol 起手，看服务暴露和服务引用的全流程（上） 在上一课时我们讲解了 Protocol 的核心接口，那本课时我们就以 Protocol 接口为核心，详细介绍整个 Protocol 的核心实现。下图展示了 Protocol 接口的继承关系： Protocol 接口继承关系图 其中，AbstractProtocol提供了一些 Prot..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-07T05:33:45.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-07T05:33:45.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"24  从 Protocol 起手，看服务暴露和服务引用的全流程（上）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-06-07T05:33:45.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"韩跑跑\\",\\"url\\":\\"https://chenmingxing1012.github.io/blog/\\"}]}"]]},"headers":[{"level":3,"title":"export 流程简析","slug":"export-流程简析","link":"#export-流程简析","children":[]},{"level":3,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"createdTime":1780673609000,"updatedTime":1780810425000,"contributors":[{"name":"chenmingxing","email":"1060303243@qq.com","commits":1}]},"readingTime":{"minutes":12.74,"words":3821},"filePathRelative":"column/Dubbo源码解读与实战/24  从 Protocol 起手，看服务暴露和服务引用的全流程（上）.md","localizedDate":"2026年6月5日","excerpt":"\\n<p>在上一课时我们讲解了 Protocol 的核心接口，那本课时我们就以 Protocol 接口为核心，详细介绍整个 Protocol 的核心实现。下图展示了 Protocol 接口的继承关系：</p>\\n<figure><figcaption></figcaption></figure>\\n<p>Protocol 接口继承关系图</p>\\n<p>其中，<strong>AbstractProtocol</strong>提供了一些 Protocol 实现需要的公共能力以及公共字段，它的核心字段有如下三个。</p>\\n<ul>\\n<li>exporterMap（<code>Map&lt;String, Exporter&lt;?&gt;&gt;</code>类型）：用于存储出去的服务集合，其中的 Key 通过 ProtocolUtils.serviceKey() 方法创建的服务标识，在 ProtocolUtils 中维护了多层的 Map 结构（如下图所示）。首先按照 group 分组，在实践中我们可以根据需求设置 group，例如，按照机房、地域等进行 group 划分，做到就近调用；在 GroupServiceKeyCache 中，依次按照 serviceName、serviceVersion、port 进行分类，最终缓存的 serviceKey 是前面三者拼接而成的。</li>\\n</ul>","autoDesc":true}')}}]);